What does the following program print?

```cpp
#include <iostream>

class Box {
private:
    int m_val{ 10 };
public:
    int& getVal()       { return m_val; }
    const int& getVal() const { return m_val; }
};

int main() {
    Box b;
    b.getVal() = 25;
    std::cout << b.getVal() << '\n';
    return 0;
}
```

The programmer wants `setViaRef` to change the stored value to 42, but the value stays at 0. What is wrong?

```cpp
#include <iostream>

class Holder {
private:
    int m_x{ 0 };
public:
    const int& getX() { return m_x; }
};

int main() {
    Holder h;
    // attempt to set m_x to 42 via the returned reference
    const int& r = h.getX();
    // r = 42;  // (this would be a compile error)
    std::cout << h.getX() << '\n';
    return 0;
}
```

What does the following program print?

```cpp
#include <iostream>

class Pair {
private:
    int m_a{ 1 };
    int m_b{ 2 };
public:
    const int& first()  const { return m_a; }
    const int& second() const { return m_b; }
};

int main() {
    const Pair p;
    std::cout << p.first() << ' ' << p.second() << '\n';
    return 0;
}
